#include <bits/stdc++.h>
using namespace std;
int n,q,sum;
char s[1000006],t[1000006];
int main(){
    ios::sync_with_stdio(0);
    cin.tie(0);
    int tmp;
    cin>>tmp;
    while(tmp--){
        sum=0;
        cin>>n>>q>>(s+1)>>(t+1);
        for(int i=1;i<=n;i++)
            sum+=(s[i]!=t[i]);
        if(sum)
            cout<<"No\n";
        else
            cout<<"Yes\n";
        while(q--){
            int a,b;
            char c;
            cin>>a>>b>>c;
            if(s[b]!=t[b])sum--;
            if(a)t[b]=c;
            else s[b]=c;
            if(s[b]!=t[b])sum++;
            if(sum)
                cout<<"No\n";
            else
                cout<<"Yes\n";
        }
    }
    return 0;
}
